router = APIRouter()

def _pd(pid): return Path(settings.projects_dir) / pid
def _mp(pid): return _pd(pid) / '.ppt_service.json'

def load_project(pid):
    p = _mp(pid)
    if not p.exists(): return None
    try: return Project(**_json.loads(p.read_text('utf-8')))
    except: return None

def save_project(proj):
    proj.touch()
    p = _mp(proj.id); p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(_json.dumps(proj.model_dump(), ensure_ascii=False, indent=2), 'utf-8')

def list_projects():
    result = []
    for p in Path(settings.projects_dir).iterdir():
        if p.is_dir():
            meta = p / '.ppt_service.json'
            if meta.exists():
                try: result.append(Project(**_json.loads(meta.read_text('utf-8'))))
                except: pass
    result.sort(key=lambda x: x.updated_at, reverse=True)
    return result

def _gpo404(pid):
    proj = load_project(pid)
    if not proj: raise HTTPException(404, f'Project {pid} not found')
    return proj

def _gst(proj):
    parts = []
    if proj.topic: parts.append('## Topic\\n' + proj.topic)
    for src in proj.sources:
        if src.converted and src.converted_path:
            fp = _pd(proj.id) / src.converted_path
            if fp.exists(): parts.append('## ' + src.original_name + '\\n' + fp.read_text(encoding='utf-8'))
    return '\\n\\n---\\n\\n'.join(parts)

import re


def _sanitize_id(name):
    safe = re.sub(r"[^\w\-]", "_", name).strip("_") or "project"
    return safe


@router.post("/api/projects")
def create_project(body: ProjectCreate):
    if load_project(body.name): raise HTTPException(400, "Already exists")
    safe_id = _sanitize_id(body.name)
    proj = Project(id=safe_id, name=body.name, format=body.format, status=ProjectStatus.created)
    proj.touch()
    ok, r = s.project_init(safe_id, body.format)
    if not ok: raise HTTPException(500, f"Init failed: {r}")
    result_path = Path(r)
    if not result_path.is_absolute():
        result_path = Path(settings.ppt_master_dir) / result_path
    if result_path.exists():
        proj.id = result_path.name
    save_project(proj)
    return proj

@router.get("/api/projects")
def get_projects(): return list_projects()

@router.get("/api/projects/{project_id}")
def get_project(project_id: str): return _gpo404(project_id)

@router.delete("/api/projects/{project_id}")
def delete_project(project_id: str):
    _gpo404(project_id)
    d = _pd(project_id)
    if d.exists(): shutil.rmtree(d)
    return {"ok": True}

