@router.post("/api/projects/{project_id}/sources")
async def upload_sources(project_id: str, files: list[UploadFile] = File(...)):
    proj = _gpo404(project_id)
    sd = _pd(project_id) / "sources"; sd.mkdir(parents=True, exist_ok=True)
    for f in files:
        fp = sd / (f.filename or "u")
        fp.write_bytes(await f.read())
        entry = SourceEntry(filename=f.filename or "u", original_name=f.filename or "u", file_type=fp.suffix.lower())
        ok, _ = s.convert_file(str(fp))
        if ok:
            entry.converted = True
            for x in sd.iterdir():
                if x.suffix == ".md" and x.stem == fp.stem: entry.converted_path = "sources/" + x.name; break
        proj.sources.append(entry)
    if proj.status == ProjectStatus.created: proj.status = ProjectStatus.sourcing
    save_project(proj)
    return {"ok": True, "sources": proj.sources}

