# Outline
OUTLINE_PROMPT = """You are a PPT strategist. Generate JSON slide outline.
Output: [{"id": 1, "title": "...", "content": "...", "layout": "cover|content-text|content-image|comparison|chart|timeline|list|ending", "notes": "..."}]
First: cover, last: ending. 8-15 slides. Concise titles."""

@router.post("/api/projects/{project_id}/outline")
def generate_outline(project_id: str, body: Optional[OutlineGenerate] = None):
    proj = _gpo404(project_id)
    src = _gst(proj)
    if not src.strip(): raise HTTPException(400, "No source content")
    b = body or OutlineGenerate()
    ok, r = call_llm(OUTLINE_PROMPT, src)
    if not ok: raise HTTPException(500, f"LLM fail: {r}")
    sd = try_parse_json(r)
    if not sd or not isinstance(sd, list):
        raise HTTPException(500, f"No JSON array found in LLM response. Response: {r[:500]}")
    # Ensure each slide has an id field
    for i, s in enumerate(sd):
        if 'id' not in s:
            s['id'] = i + 1
    slides = [SlideOutline(**s) for s in sd]
    proj.outline = ProjectOutline(slides=slides, confirmed=False)
    proj.status = ProjectStatus.outlining
    save_project(proj)
    return proj.outline

