# Generation pipeline helpers
def _gen_design_spec(proj, pd_):
    c = proj.design.colors; f_ = proj.design.fonts
    sj = _json.dumps([s.model_dump() for s in proj.outline.slides], ensure_ascii=False, indent=2)
    sp = "You are PPT Strategist. Make design_spec.md.\nStyle: " + proj.design.style_id + "\nColors: primary=" + c.primary + "\nFonts: heading=" + f_.heading + "\nOutline:\n" + sj
    ok, r = call_llm(sp, "Generate.")
    if not ok: return False, r
    (pd_ / "design_spec.md").write_text(r, "utf-8")
    (pd_ / "spec_lock.md").write_text(r, "utf-8")
    return True, r

def _gen_svg(proj, slide, pd_):
    c = proj.design.colors; f_ = proj.design.fonts
    sp = ("You are PPT Executor. SVG slide.\n" + str(slide.id) + ": " + slide.title +
        "\nLayout: " + slide.layout + "\nContent: " + slide.content +
        "\nColors: primary=" + c.primary + " bg=" + c.background +
        "\nFonts: " + f_.heading + "\n1920x1080\nOutput ONLY SVG.")
    ok, r = call_llm(sp, "Gen page " + str(slide.id), max_tokens=8192)
    if not ok: return False, r
    m = re.search(r"<svg[\s\S]*?</svg>", r, re.IGNORECASE)
    svgc = m.group() if m else r
    # Fix unescaped & in XML (e.g. Google Fonts URLs)
    svgc = re.sub(r'&(?!amp;|lt;|gt;|quot;|apos;|#\d+;|#x[\da-fA-F]+;)', '&amp;', svgc)
    sd = pd_ / "svg_output"; sd.mkdir(parents=True, exist_ok=True)
    (sd / ("page_%02d.svg" % slide.id)).write_text(svgc, "utf-8")
    return True, "page_%02d.svg" % slide.id

def _gen_notes(proj, pd_):
    nd = pd_ / "notes"; nd.mkdir(parents=True, exist_ok=True)
    lines = ["## Page %d: %s\n%s" % (s.id, s.title, s.notes or s.content) for s in proj.outline.slides]
    (nd / "total.md").write_text("\n\n".join(lines), "utf-8")

# Pipeline runner
def _run_pipeline(pid, tid):
    task = load_task(tid)
    if not task: return
    pdir = _pd(pid); proj = load_project(pid)
    if not proj: set_task_error(task, "No project"); return
    try:
        update_task_status(task, "running", 0.05, "Design spec")
        update_step(task, 0, "running", "Design spec...")
        ok, r = _gen_design_spec(proj, pdir)
        if not ok: set_task_error(task, "Design: " + r); return
        update_step(task, 0, "completed", "Design spec done")

        slides = proj.outline.slides; total = len(slides)
        if total == 0: set_task_error(task, "No slides"); return
        update_step(task, 1, "running", "1/" + str(total))
        for i, sl in enumerate(slides):
            p = 0.1 + 0.7 * ((i + 1) / total)
            update_task_status(task, "running", p, "SVG " + str(i + 1) + "/" + str(total))
            update_step(task, 1, "running", str(i + 1) + "/" + str(total))
            ok2, r2 = _gen_svg(proj, sl, pdir)
            if not ok2:
                t = load_task(tid)
                if t: t.steps[1].detail += " | P" + str(i + 1) + " fail: " + r2[:80]
        update_step(task, 1, "completed", str(total) + " SVGs done")

        update_task_status(task, "running", 0.85, "Notes")
        update_step(task, 2, "running", "Notes...")
        _gen_notes(proj, pdir)
        update_step(task, 2, "completed", "Notes done")

        update_task_status(task, "running", 0.9, "Exporting...")
        update_step(task, 3, "running", "Export...")
        s.run_total_md_split(str(pdir))
        s.run_finalize_svg(str(pdir))
        ok3, r3 = s.run_svg_to_pptx(str(pdir))
        update_step(task, 3, "completed" if ok3 else "failed", r3[:200] if r3 else "")

        ex = pdir / "exports"
        ppts = sorted(ex.glob("*.pptx")) if ex.exists() else []
        if ppts:
            proj.status = ProjectStatus.done
            proj.task_id = None
            save_project(proj)
            set_task_result(task, {"export_path": "api/projects/" + pid + "/exports/" + ppts[-1].name})
        elif ok3:
            proj.status = ProjectStatus.done
            proj.task_id = None
            save_project(proj)
            set_task_result(task, {"message": "Export done"})
        else:
            proj.status = ProjectStatus.failed
            proj.task_id = None
            save_project(proj)
            set_task_error(task, "Export failed")
    except Exception as e:
        proj.status = ProjectStatus.failed
        proj.task_id = None
        save_project(proj)
        t = load_task(tid)
        if t: set_task_error(t, str(e))

# Generate trigger
@router.post("/api/projects/{project_id}/generate")
def submit_generation(project_id: str, body: Optional[GenerateRequest] = None):
    proj = _gpo404(project_id)
    if proj.status == ProjectStatus.generating: raise HTTPException(400, "Already generating")
    b = body or GenerateRequest()
    task = create_task(project_id=project_id, steps=["Design", "SVG", "Notes", "Export"])
    proj.status = ProjectStatus.generating
    proj.task_id = task.task_id
    save_project(proj)
    t = threading.Thread(target=_run_pipeline, args=(project_id, task.task_id), daemon=True)
    t.start()
    return {"task_id": task.task_id, "status": "running"}

