# SVG management
@router.post("/api/projects/{project_id}/svg")
async def upload_svg(project_id: str, files: list[UploadFile] = File(...)):
    _gpo404(project_id)
    sd = _pd(project_id) / "svg_output"; sd.mkdir(parents=True, exist_ok=True)
    ul = []
    for f in files:
        if not f.filename or not f.filename.endswith(".svg"): continue
        (sd / f.filename).write_bytes(await f.read()); ul.append(f.filename)
    return {"ok": True, "uploaded": ul}

